<?php defined('_JEXEC') or die; $days=[1=>'Lunedi',2=>'Martedi',3=>'Mercoledi',4=>'Giovedi',5=>'Venerdi',6=>'Sabato',7=>'Domenica']; ?>
<h1>Fasce orarie Sala OV</h1><table class="table"><tr><th>Giorno</th><th>Titolo</th><th>Orario</th><th>Capienza</th><th>Pubblicata</th><th></th></tr><?php foreach($this->items as $r): ?><tr><td><?php echo $days[$r->weekday]; ?></td><td><?php echo htmlspecialchars($r->title); ?></td><td><?php echo substr($r->start_time,0,5).' - '.substr($r->end_time,0,5); ?></td><td><?php echo (int)$r->capacity; ?></td><td><?php echo $r->published?'Si':'No'; ?></td><td><a class="btn btn-sm btn-danger" href="index.php?option=com_salaov&task=slots.delete&id=<?php echo (int)$r->id; ?>">Elimina</a></td></tr><?php endforeach; ?></table>
<h2>Nuova fascia</h2><form method="post" action="index.php?option=com_salaov&task=slots.save" class="form-grid"><input name="title" placeholder="Titolo" required> <select name="weekday"><?php foreach($days as $n=>$d) echo '<option value="'.$n.'">'.$d.'</option>'; ?></select> <input type="time" name="start_time" required> <input type="time" name="end_time" required> <input type="number" name="capacity" min="1" value="20" required> <select name="published"><option value="1">Pubblicata</option><option value="0">Non pubblicata</option></select> <button class="btn btn-primary">Salva</button></form>
